def gestionar_pedido(almacen, id_pedido, notificador=None):
    class PedidoProcessor:
        def __init__(self, almacen):
            # Inyección por constructor (obligatoria)
            self.almacen = almacen
            self.notificador = None

        def asignar_notificador(self, notificador):
            # Inyección por setter (opcional)
            self.notificador = notificador

        def procesar(self, id_p):
            mensaje = self.almacen.guardar(id_p)
            if self.notificador:
                return f"{mensaje} (con aviso)"
            return mensaje

    procesador = PedidoProcessor(almacen)
    if notificador:
        procesador.asignar_notificador(notificador)

    return procesador.procesar(id_pedido)

